def find_median_sorted_arrays(nums1, nums2):
    total = len(nums1) + len(nums2)
    if total % 2 == 1:
        return find_kth(nums1, nums2, total // 2)
    else:
        return (find_kth(nums1, nums2, total // 2 - 1) + find_kth(nums1, nums2, total // 2)) / 2

def find_kth(nums1, nums2, k):
    if len(nums1) == 0:
        return nums2[k]
    if len(nums2) == 0:
        return nums1[k]

    i = len(nums1) // 2
    j = len(nums2) // 2

    if i + j < k:
        if nums1[i] > nums2[j]:
            return find_kth(nums1, nums2[j+1:], k - j - 1)
        else:
            return find_kth(nums1[i+1:], nums2, k - i - 1)
    else:
        if nums1[i] > nums2[j]:
            return find_kth(nums1[:i], nums2, k)
        else:
            return find_kth(nums1, nums2[:j], k)
